/**
 * Fix broken table column widths in docx generated by @mohtasham/md-to-docx.
 * That tool often emits gridCol w:w="100" (~0.07 inch), causing vertical text in Word/Tencent Docs.
 */
import fs from 'fs'
import path from 'path'
import { execSync } from 'child_process'
import { fileURLToPath } from 'url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const TABLE_WIDTH = 9746 // dxa, matches md-to-docx default tblW

function fixDocumentXml(xml) {
  return xml.replace(/<w:tbl>([\s\S]*?)<\/w:tbl>/g, (tblBlock) => {
    const gridMatch = tblBlock.match(/<w:tblGrid>([\s\S]*?)<\/w:tblGrid>/)
    if (!gridMatch) return tblBlock

    const colCount = (gridMatch[1].match(/<w:gridCol/g) || []).length
    if (colCount === 0) return tblBlock

    const widths = Array.from({ length: colCount }, (_, i) => {
      const base = Math.floor(TABLE_WIDTH / colCount)
      const remainder = TABLE_WIDTH - base * colCount
      return base + (i < remainder ? 1 : 0)
    })

    const newGrid = `<w:tblGrid>${widths.map((w) => `<w:gridCol w:w="${w}"/>`).join('')}</w:tblGrid>`

    let fixed = tblBlock.replace(/<w:tblGrid>[\s\S]*?<\/w:tblGrid>/, newGrid)
    fixed = fixed.replace(/<w:tblLayout w:type="autofit"\/>/, '<w:tblLayout w:type="fixed"/>')
    return fixed
  })
}

function fixDocx(inputPath, outputPath) {
  const tmp = fs.mkdtempSync(path.join(process.env.TEMP || '/tmp', 'docx-fix-'))
  const zipPath = path.join(tmp, 'doc.zip')
  fs.copyFileSync(inputPath, zipPath)
  execSync(`powershell -NoProfile -Command "Expand-Archive -Path '${zipPath.replace(/'/g, "''")}' -DestinationPath '${path.join(tmp, 'unz').replace(/'/g, "''")}' -Force"`)

  const docXmlPath = path.join(tmp, 'unz', 'word', 'document.xml')
  const xml = fs.readFileSync(docXmlPath, 'utf8')
  fs.writeFileSync(docXmlPath, fixDocumentXml(xml), 'utf8')

  if (fs.existsSync(outputPath)) fs.unlinkSync(outputPath)
  execSync(
    `powershell -NoProfile -Command "Compress-Archive -Path '${path.join(tmp, 'unz', '*').replace(/'/g, "''")}' -DestinationPath '${zipPath.replace(/'/g, "''")}' -Force"`,
  )
  fs.copyFileSync(zipPath, outputPath)
  fs.rmSync(tmp, { recursive: true, force: true })
  console.log(`Fixed: ${outputPath}`)
}

const input =
  process.argv[2] ||
  path.resolve(__dirname, '../docs/灵鱿科技远程监控与控制协议-V1.0.0.docx')
const output = process.argv[3] || input
fixDocx(input, output)
